INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops position ownership, alignment, and low-speed joint resilience for safer Output and Capacity.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('dead-bug-heel-tap-control-progression', 'The dead bug trains anti-extension: the athlete moves the limbs while resisting lumbar arching and rib flare — fundamental spinal control and coordination through alternating limb movement.', 'Belongs in anti_extension_control (531) — default supine anti-extension drill before loaded or plank progressions.', '', 'Control is trunk precision — resist compensation, breathe under tension, and own rib/pelvis position. Not ab-burn Fitness circuits, Capacity loading, or high-rep core fatigue work.', 'Regress to feet-down heel slide or hands-on-ribs before reducing tap quality; hypermobility athletes need active control — avoid over-flattening or hanging into end range.'),
  ('dead-bug-pullover-band-dead-bug', 'Adding resistance to the dead bug increases anti-extension demand — the athlete must keep ribs and pelvis organized while arm load tries to pull the trunk open.', 'Belongs in loaded_anti_extension_control (532) — loaded progression after basic dead bug heel tap control.', '', 'Control is trunk precision — resist compensation, breathe under tension, and own rib/pelvis position. Not ab-burn Fitness circuits, Capacity loading, or high-rep core fatigue work.', 'Reduce load and overhead range before reducing rib control; hypermobility athletes need smaller ranges — do not hang into shoulder or lumbar extension.'),
  ('bird-dog-iso-hold', 'Bird dog trains the athlete to stabilize the lumbar spine while moving opposite upper and lower limbs — anti-rotation and cross-body trunk control from a low-risk quadruped base.', 'Belongs in contralateral_trunk_control (533) — quadruped cross-body control before bear plank and crawling.', '', 'Control is trunk precision — resist compensation, breathe under tension, and own rib/pelvis position. Not ab-burn Fitness circuits, Capacity loading, or high-rep core fatigue work.', 'Use leg-only or arm-only before full contralateral reach; hypermobility athletes need active reach — avoid over-reaching and lumbar extension.'),
  ('front-plank-long-lever-plank', 'The plank is a fundamental isometric anti-extension core drill — building postural endurance and trunk stiffness while the shoulders support body weight.', 'Belongs in anterior_trunk_control (534) — foundational anti-extension hold before dynamic plank or long-lever progressions.', '', 'Control is trunk precision — resist compensation, breathe under tension, and own rib/pelvis position. Not ab-burn Fitness circuits, Capacity loading, or high-rep core fatigue work.', 'End set when hips sag — quality beats duration; hypermobility athletes need active shoulder and trunk tension — avoid hanging into lumbar extension or shoulder joints.'),
  ('side-plank', 'Side plank trains lateral trunk control and teaches the athlete to resist side bending — foundational anti-lateral-flexion work for carries and frontal-plane demands.', 'Belongs in lateral_trunk_control (535) — default anti-lateral-flexion hold before Copenhagen or loaded carry progressions.', '', 'Control is trunk precision — resist compensation, breathe under tension, and own rib/pelvis position. Not ab-burn Fitness circuits, Capacity loading, or high-rep core fatigue work.', 'Use modified/knee side plank when hips sag or torso rotates; hypermobility athletes need active press into floor — avoid hanging into shoulder.'),
  ('bear-plank-hold', 'Bear plank creates a short-lever quadruped trunk-control task — preparing athletes for crawling and hand-support patterns where the trunk must stay quiet under load.', 'Belongs in quadruped_trunk_control (536) — crawling-base stability before bear shoulder taps and crawls.', '', 'Control is trunk precision — resist compensation, breathe under tension, and own rib/pelvis position. Not ab-burn Fitness circuits, Capacity loading, or high-rep core fatigue work.', 'Use dead bug, bird dog, or elevated quadruped when wrist pain or pressure symptoms appear; hypermobility athletes need active wrist/shoulder press.'),
  ('bear-plank-shoulder-tap', 'Shoulder taps train trunk stabilization while one hand leaves the ground — anti-rotation control from a shorter quadruped base than tall plank shoulder taps.', 'Belongs in anti_rotation_quadruped_control (537) — dynamic anti-rotation after bear plank hold.', '', 'Control is trunk precision — resist compensation, breathe under tension, and own rib/pelvis position. Not ab-burn Fitness circuits, Capacity loading, or high-rep core fatigue work.', 'Widen base and slow taps when hips rotate; hypermobility athletes need active floor press — avoid dumping into wrists/shoulders.'),
  ('plank-pull-through', 'Plank pull-through combines anti-extension with an arm reach that tries to rotate the pelvis — training anti-rotation control from a hand-supported plank position.', 'Belongs in dynamic_anti_rotation_control (538) — loaded reach anti-rotation after bear shoulder tap control.', '', 'Control is trunk precision — resist compensation, breathe under tension, and own rib/pelvis position. Not ab-burn Fitness circuits, Capacity loading, or high-rep core fatigue work.', 'Use lighter object, wider feet, or Pallof hold when pelvis rotates; hypermobility athletes need active wrist/shoulder support.'),
  ('pallof-press-iso-hold', 'Pallof press trains the athlete to resist rotation from a band or cable — pressing or holding the handle away while keeping the torso square to the front.', 'Belongs in anti_rotation_hold (539) — default standing anti-rotation control before half-kneeling or rotational progressions.', '', 'Control is trunk precision — resist compensation, breathe under tension, and own rib/pelvis position. Not ab-burn Fitness circuits, Capacity loading, or high-rep core fatigue work.', 'Reduce resistance or shorten lever when torso rotates; hypermobility athletes need active stacked posture — avoid passive leaning.'),
  ('half-kneeling-anti-rotation-press-lift-hold', 'Half-kneeling anti-rotation constrains the lower body and forces pelvis and trunk control while resisting band/cable pull — exposing compensation that standing may hide.', 'Belongs in half_kneeling_trunk_control (540) — split-stance anti-rotation after standing Pallof control.', '', 'Control is trunk precision — resist compensation, breathe under tension, and own rib/pelvis position. Not ab-burn Fitness circuits, Capacity loading, or high-rep core fatigue work.', 'Use standing Pallof hold when pelvis rotates; hypermobility athletes need active back glute — avoid passive hip extension.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();
